187→export default function WindowRenderer({ windows, walls }) {
188→  return (
189→    <g className="windows">
190→      {windows.map(win => {
191→        const wall = walls.find(w => w.id === win.wallId);
192→        if (!wall) return null;
193→
194→        const info = windowOutlineOnWall(wall, win);
195→        const type = win.type || 'standard';
196→
197→        return (
198→          <g key={win.id} data-id={win.id} data-type="window">
199→            {/* White rectangle to mask wall */}
200→            <polygon
201→              points={`${info.p1.x},${info.p1.y} ${info.p2.x},${info.p2.y} ${info.p3.x},${info.p3.y} ${info.p4.x},${info.p4.y}`}
202→              fill="white"
203→              stroke="none"
204→            />
205→            {type === 'standard' && <StandardWindow info={info} wall={wall} />}
206→            {type === 'casement' && <CasementWindow win={win} info={info} />}
207→            {type === 'awning' && <AwningWindow win={win} info={info} />}
208→            {type === 'fixed' && <FixedWindow info={info} />}
209→            {type === 'jalousie' && <JalousieWindow win={win} info={info} wall={wall} />}
210→          </g>
211→        );
212→      })}
213→    </g>
214→  );
215→}
