 44→export default function Toolbar({
 45→  onNew,
 46→  onSave,
 47→  onLoad,
 48→  isSidebarCollapsed,
 49→  isPropertiesCollapsed,
 50→  onToggleSidebar,
 51→  onToggleProperties,
 52→}) {
 53→  const { activeTool, showGrid, snapEnabled, activeFloorId, viewMode, workspaceMode, dispatch: editorDispatch } = useEditor();
 54→  const { project, isDirty, canUndo, canRedo, dispatch } = useProject();
 55→  const {
 56→    canCopySelection,
 57→    canPaste,
 58→    copySelection,
 59→    cutSelection,
 60→    beginPaste,
 61→  } = usePlanClipboardController();
 62→  const isPlanView = workspaceMode === 'model' && viewMode === 'plan';
 63→
 64→  const setTool = (tool) => editorDispatch({ type: 'SET_TOOL', tool });
 65→
 66→  const handleUndo = useCallback(() => {
 67→    if (!canUndo) return;
 68→    dispatch({ type: 'UNDO' });
 69→    editorDispatch({ type: 'DESELECT' });
 70→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Undid last change.' });
 71→  }, [canUndo, dispatch, editorDispatch]);
 72→
 73→  const handleRedo = useCallback(() => {
 74→    if (!canRedo) return;
 75→    dispatch({ type: 'REDO' });
 76→    editorDispatch({ type: 'DESELECT' });
 77→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Redid last change.' });
 78→  }, [canRedo, dispatch, editorDispatch]);
 79→
 80→  const handleDetectRooms = () => {
 81→    const floor = project.floors.find(f => f.id === activeFloorId);
 82→    if (!floor || floor.walls.length < 3) {
 83→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Draw at least 3 walls first.' });
 84→      return;
 85→    }
 86→    const detected = detectRooms(floor.walls, floor.columns || []);
 87→    const rooms = detected.map((d, i) => createRoom(`Room ${i + 1}`, d.points));
 88→    dispatch({ type: 'ROOMS_SET', floorId: activeFloorId, rooms });
 89→    editorDispatch({ type: 'DESELECT' });
 90→    editorDispatch({
 91→      type: 'SET_STATUS_MESSAGE',
 92→      message: rooms.length ? `Detected ${rooms.length} room${rooms.length === 1 ? '' : 's'}.` : 'No enclosed rooms detected.',
 93→    });
 94→  };
 95→
 96→  useEffect(() => {
 97→    const handleKeyDown = (e) => {
 98→      if (!(e.ctrlKey || e.metaKey)) return;
 99→      if (isTypingTarget(e.target)) return;
100→
101→      const key = e.key.toLowerCase();
102→      const isRedo = (key === 'z' && e.shiftKey) || key === 'y';
103→      const isUndo = key === 'z' && !e.shiftKey;
104→      if (!isUndo && !isRedo) return;
105→
106→      e.preventDefault();
107→      if (isRedo) {
108→        handleRedo();
109→        return;
110→      }
111→      handleUndo();
112→    };
113→
114→    window.addEventListener('keydown', handleKeyDown);
115→    return () => window.removeEventListener('keydown', handleKeyDown);
116→  }, [handleRedo, handleUndo]);
117→
118→  const activeViewKey = workspaceMode === 'sheet' ? 'sheets' :
119→    viewModes.find(v => v.viewMode === viewMode)?.key || 'plan';
120→
121→  return (
122→    <div className={styles.toolbar}>
123→      {/* File & clipboard actions */}
124→      <div className={styles.group}>
125→        <button className={styles.btn} onClick={onNew} title="New Project">
126→          <NewIcon className={styles.icon} />
127→        </button>
128→        <button
129→          className={styles.btn}
130→          onClick={handleUndo}
131→          disabled={!canUndo}
132→          title="Undo (Ctrl+Z)"
133→          aria-label="Undo"
134→        >
135→          <UndoIcon className={styles.icon} />
136→        </button>
137→        <button
138→          className={styles.btn}
139→          onClick={handleRedo}
140→          disabled={!canRedo}
141→          title="Redo (Ctrl+Shift+Z)"
142→          aria-label="Redo"
143→        >
144→          <RedoIcon className={styles.icon} />
145→        </button>
146→        <button
147→          className={styles.saveBtn}
148→          onClick={onSave}
149→          title="Save (Ctrl+S)"
150→          data-dirty={isDirty}
151→        >
152→          <SaveIcon className={styles.icon} />
153→        </button>
154→        <div className={styles.divider} />
155→        <button className={styles.btn} onClick={onLoad} title="Load Project">
156→          <LoadIcon className={styles.icon} />
157→        </button>
158→        <button
159→          className={styles.btn}
160→          onClick={copySelection}
161→          disabled={!canCopySelection}
162→          title="Copy (Ctrl+C)"
163→        >
164→          <CopyIcon className={styles.icon} />
165→        </button>
166→        <button
167→          className={styles.btn}
168→          onClick={cutSelection}
169→          disabled={!canCopySelection}
170→          title="Cut (Ctrl+X)"
171→        >
172→          <CutIcon className={styles.icon} />
173→        </button>
174→        <button
175→          className={styles.btn}
176→          onClick={() => beginPaste()}
177→          disabled={!canPaste}
178→          title="Paste (Ctrl+V)"
179→        >
180→          <PasteIcon className={styles.icon} />
181→        </button>
182→      </div>
183→
184→      {/* View mode segmented control */}
185→      <div className={styles.segmentedGroup}>
186→        {viewModes.map(({ key, label, viewMode: vm }) => (
187→          <button
188→            key={key}
189→            className={activeViewKey === key ? styles.segmentedBtnActive : styles.segmentedBtn}
190→            onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: vm })}
191→            title={`${label} View`}
192→          >
193→            {label}
194→          </button>
195→        ))}
196→        <button
197→          className={activeViewKey === 'sheets' ? styles.segmentedBtnActive : styles.segmentedBtn}
198→          onClick={() => editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' })}
199→          title="Sheet Workspace"
200→        >
201→          Sheets
202→        </button>
203→      </div>
204→
205→      {/* Tool palette - inline row of 12 icons */}
206→      <div className={styles.toolPalette}>
207→        {toolItems.map(({ tool, label, shortcut, Icon }) => (
208→          <button
209→            key={tool}
210→            className={activeTool === tool ? styles.toolPaletteBtnActive : styles.toolPaletteBtn}
211→            onClick={() => setTool(tool)}
212→            disabled={!isPlanView}
213→            title={`${label} (${shortcut})`}
214→            aria-label={label}
215→          >
216→            <Icon className={styles.toolPaletteIcon} />
217→          </button>
218→        ))}
219→      </div>
220→
221→      {/* Panel toggles & utility toggles */}
222→      <div className={styles.group}>
223→        <button
224→          className={`${styles.toggleBtn} ${!isSidebarCollapsed ? styles.toggleActive : ''}`}
225→          onClick={onToggleSidebar}
226→          title={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
227→          aria-label={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
228→        >
229→          <SidebarIcon className={styles.icon} />
230→        </button>
231→        <button
232→          className={`${styles.toggleBtn} ${!isPropertiesCollapsed ? styles.toggleActive : ''}`}
233→          onClick={onToggleProperties}
234→          title={isPropertiesCollapsed ? 'Show Properties' : 'Hide Properties'}
235→          aria-label={isPropertiesCollapsed ? 'Show Properties' : 'Hide Properties'}
236→        >
237→          <PropertiesIcon className={styles.icon} />
238→        </button>
239→        <div className={styles.divider} />
240→        <button
241→          className={`${styles.toggleBtn} ${showGrid ? styles.toggleActive : ''}`}
242→          onClick={() => editorDispatch({ type: 'TOGGLE_GRID' })}
243→          title="Toggle Grid"
244→          aria-label="Toggle Grid"
245→        >
246→          <GridIcon className={styles.icon} />
247→        </button>
248→        <button
249→          className={`${styles.toggleBtn} ${snapEnabled ? styles.toggleActive : ''}`}
250→          onClick={() => editorDispatch({ type: 'TOGGLE_SNAP' })}
251→          title="Toggle Snap"
252→          aria-label="Toggle Snap"
253→        >
254→          <SnapIcon className={styles.icon} />
255→        </button>
256→        <button
257→          className={styles.btn}
258→          onClick={handleDetectRooms}
259→          title="Auto-detect Rooms"
260→          disabled={!isPlanView}
261→          aria-label="Auto-detect Rooms"
262→        >
263→          <DetectRoomsIcon className={styles.icon} />
264→        </button>
265→      </div>
266→
267→      <div className={styles.spacer} />
268→    </div>
269→  );
