 29→function updateFloor(state, floorId, updater, recordHistory = true, options = {}) {
 30→  const nextFloors = state.project.floors.map((floor) => (
 31→    floor.id === floorId ? updater(floor) : floor
 32→  ));
 33→
 34→  return applyProjectUpdate(state, {
 35→    ...state.project,
 36→    updatedAt: new Date().toISOString(),
 37→    floors: options.sort ? sortFloors(nextFloors) : nextFloors,
 38→  }, recordHistory);
 39→}
