 41→function replaceFloors(state, floors, recordHistory = true) {
 42→  return applyProjectUpdate(state, {
 43→    ...state.project,
 44→    updatedAt: new Date().toISOString(),
 45→    floors: sortFloors(floors),
 46→  }, recordHistory);
 47→}
