108→export function createSelectHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled }) {
109→  return {
110→    onMouseDown(modelPos, e, toolState) {
111→      if (e.button !== 0) return;
112→
113→      const floor = getFloor(activeFloorId);
114→      if (!floor) return;
115→
116→      // Check if clicking a handle
117→      const target = e.target;
118→      if (target.dataset.handle) {
119→        editorDispatch({
120→          type: 'UPDATE_TOOL_STATE',
121→          payload: {
122→            dragging: true,
123→            dragType: 'handle',
124→            handle: target.dataset.handle,
125→            handleIndex: target.dataset.index != null ? Number(target.dataset.index) : null,
126→            startPos: modelPos,
127→          },
128→        });
129→        return;
130→      }
131→
132→      const hit = hitTest(modelPos, floor, SNAP_DISTANCE_PX / viewport.zoom * 2.5);
133→      if (hit) {
134→        editorDispatch({ type: 'SELECT_OBJECT', id: hit.id, objectType: hit.type });
135→        const draggableTypes = new Set(['wall', 'column', 'door', 'window', 'stair', 'sectionCut', 'landing']);
136→        if (!draggableTypes.has(hit.type)) return;
137→        editorDispatch({
138→          type: 'UPDATE_TOOL_STATE',
139→          payload: {
140→            dragging: true,
141→            dragType: 'move',
142→            startPos: modelPos,
143→            originalPos: modelPos,
144→          },
145→        });
146→      } else {
147→        editorDispatch({
148→          type: 'UPDATE_TOOL_STATE',
149→          payload: {
150→            dragging: true,
151→            dragType: 'marquee',
152→            startPos: modelPos,
153→            currentPos: modelPos,
154→          },
155→        });
156→      }
157→    },
158→
159→    onMouseMove(modelPos, e, toolState, selectedId, selectedType) {
160→      if (toolState.dragging && toolState.dragType === 'marquee') {
161→        editorDispatch({
162→          type: 'UPDATE_TOOL_STATE',
163→          payload: { currentPos: modelPos },
164→        });
165→        return;
166→      }
167→
168→      if (!toolState.dragging || !selectedId) return;
169→
170→      const floor = getFloor(activeFloorId);
171→      if (!floor) return;
172→      const dx = modelPos.x - toolState.startPos.x;
173→      const dy = modelPos.y - toolState.startPos.y;
174→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
175→
176→      if (selectedType === 'wall') {
177→        const wall = floor.walls.find(w => w.id === selectedId);
178→        if (!wall) return;
179→        const resolved = resolveWallEndpoints(wall, floor.columns || []);
180→
181→        if (toolState.dragType === 'handle') {
182→          const handle = toolState.handle;
183→          const oppositeKey = handle === 'start' ? 'end' : 'start';
184→          const oppositePoint = resolved[oppositeKey];
185→          let nextPoint = modelPos;
186→          let nextAttachment = null;
187→
188→          if (e.shiftKey) {
189→            const dx = modelPos.x - oppositePoint.x;
190→            const dy = modelPos.y - oppositePoint.y;
191→            const angle = Math.atan2(dy, dx);
192→            const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
193→            const len = Math.sqrt(dx * dx + dy * dy);
194→            nextPoint = {
195→              x: oppositePoint.x + Math.cos(snapAngle) * len,
196→              y: oppositePoint.y + Math.sin(snapAngle) * len,
197→            };
198→          } else if (snapEnabled) {
199→            const snapResult = snapWallEndpoint(modelPos, {
200→              walls: floor.walls,
201→              columns: floor.columns || [],
202→              snapDist: snapDistModel,
203→              otherPoint: oppositePoint,
204→              ignoreWallId: wall.id,
205→            });
206→            if (snapResult) {
207→              nextPoint = snapResult.point;
208→              nextAttachment = snapResult.attachment;
209→            }
210→          }
211→
212→          if (distance(nextPoint, oppositePoint) < MIN_WALL_LENGTH) return;
213→
214→          dispatch({
215→            type: 'WALL_UPDATE',
216→            floorId: activeFloorId,
217→            wall: {
218→              id: wall.id,
219→              [handle]: nextPoint,
220→              [`${handle}Attachment`]: nextAttachment,
221→            },
222→          });
223→        } else {
224→          let nextStart = { x: resolved.start.x + dx, y: resolved.start.y + dy };
225→          let nextEnd = { x: resolved.end.x + dx, y: resolved.end.y + dy };
226→          let startAttachment = null;
227→          let endAttachment = null;
228→
229→          if (snapEnabled) {
230→            const startSnap = snapWallEndpoint(nextStart, {
231→              walls: floor.walls,
232→              columns: floor.columns || [],
233→              snapDist: snapDistModel,
234→              otherPoint: nextEnd,
235→              ignoreWallId: wall.id,
236→            });
237→            if (startSnap) {
238→              nextStart = startSnap.point;
239→              startAttachment = startSnap.attachment;
240→            }
241→
242→            const endSnap = snapWallEndpoint(nextEnd, {
243→              walls: floor.walls,
244→              columns: floor.columns || [],
245→              snapDist: snapDistModel,
246→              otherPoint: nextStart,
247→              ignoreWallId: wall.id,
248→            });
249→            if (endSnap) {
250→              nextEnd = endSnap.point;
251→              endAttachment = endSnap.attachment;
252→            }
253→          }
254→
255→          if (distance(nextStart, nextEnd) < MIN_WALL_LENGTH) return;
256→
257→          dispatch({
258→            type: 'WALL_UPDATE',
259→            floorId: activeFloorId,
260→            wall: {
261→              id: wall.id,
262→              start: nextStart,
263→              end: nextEnd,
264→              startAttachment,
265→              endAttachment,
266→            },
267→          });
268→        }
269→        editorDispatch({
270→          type: 'UPDATE_TOOL_STATE',
271→          payload: { startPos: modelPos },
272→        });
273→      } else if (selectedType === 'column') {
274→        const col = (floor.columns || []).find(c => c.id === selectedId);
275→        if (!col) return;
276→        dispatch({
277→          type: 'COLUMN_UPDATE',
278→          floorId: activeFloorId,
279→          column: { id: col.id, x: col.x + dx, y: col.y + dy },
280→        });
281→        editorDispatch({
282→          type: 'UPDATE_TOOL_STATE',
283→          payload: { startPos: modelPos },
284→        });
285→      } else if (selectedType === 'sectionCut') {
286→        const sectionCut = (floor.sectionCuts || []).find(s => s.id === selectedId);
287→        if (!sectionCut) return;
288→
289→        if (toolState.dragType === 'handle') {
290→          const handle = toolState.handle;
291→          const nextSectionCut = handle === 'start'
292→            ? { ...sectionCut, startPoint: modelPos }
293→            : { ...sectionCut, endPoint: modelPos };
294→
295→          if (distance(nextSectionCut.startPoint, nextSectionCut.endPoint) < MIN_WALL_LENGTH) return;
296→
297→          dispatch({
298→            type: 'SECTION_UPDATE',
299→            floorId: activeFloorId,
300→            sectionCut: nextSectionCut,
301→          });
302→        } else {
303→          dispatch({
304→            type: 'SECTION_UPDATE',
305→            floorId: activeFloorId,
306→            sectionCut: {
307→              id: sectionCut.id,
308→              startPoint: {
309→                x: sectionCut.startPoint.x + dx,
310→                y: sectionCut.startPoint.y + dy,
311→              },
312→              endPoint: {
313→                x: sectionCut.endPoint.x + dx,
314→                y: sectionCut.endPoint.y + dy,
315→              },
316→            },
317→          });
318→          editorDispatch({
319→            type: 'UPDATE_TOOL_STATE',
320→            payload: { startPos: modelPos },
321→          });
322→        }
323→      } else if (selectedType === 'beam') {
324→        return;
325→      } else if (selectedType === 'stair') {
326→        const stair = (floor.stairs || []).find(entry => entry.id === selectedId);
327→        if (!stair) return;
328→        dispatch({
329→          type: 'STAIR_UPDATE',
330→          floorId: activeFloorId,
331→          stair: {
332→            id: stair.id,
333→            startPoint: {
334→              x: stair.startPoint.x + dx,
335→              y: stair.startPoint.y + dy,
336→            },
337→          },
338→        });
339→        editorDispatch({
340→          type: 'UPDATE_TOOL_STATE',
341→          payload: { startPos: modelPos },
342→        });
343→      } else if (selectedType === 'landing') {
344→        const landing = (floor.landings || []).find(l => l.id === selectedId);
345→        if (!landing) return;
346→        dispatch({
347→          type: 'LANDING_UPDATE',
348→          floorId: activeFloorId,
349→          landing: {
350→            id: landing.id,
351→            position: {
352→              x: landing.position.x + dx,
353→              y: landing.position.y + dy,
354→            },
355→          },
356→        });
357→        editorDispatch({
358→          type: 'UPDATE_TOOL_STATE',
359→          payload: { startPos: modelPos },
360→        });
361→      } else if (selectedType === 'slab') {
362→        if (toolState.dragType !== 'handle' || toolState.handle !== 'slab-vertex' || toolState.handleIndex == null) {
363→          return;
364→        }
365→        const slab = (floor.slabs || []).find(s => s.id === selectedId);
366→        if (!slab) return;
367→
368→        const boundaryPoints = slab.boundaryPoints.map((point, index) => (
369→          index === toolState.handleIndex ? { x: modelPos.x, y: modelPos.y } : point
370→        ));
371→
372→        dispatch({
373→          type: 'SLAB_UPDATE',
374→          floorId: activeFloorId,
375→          slab: {
376→            id: slab.id,
377→            boundaryPoints,
378→          },
379→        });
380→        editorDispatch({
381→          type: 'UPDATE_TOOL_STATE',
382→          payload: { startPos: modelPos },
383→        });
384→      } else if (selectedType === 'door' || selectedType === 'window') {
385→        // Slide along parent wall
386→        const items = selectedType === 'door' ? floor.doors : floor.windows;
387→        const item = items.find(i => i.id === selectedId);
388→        if (!item) return;
389→
390→        const wall = floor.walls.find(w => w.id === item.wallId);
391→        if (!wall) return;
392→
393→        const newOffset = projectPointOnWall(wall, modelPos);
394→        const halfWidth = item.width / 2;
395→        const maxOffset = wallLength(wall) - halfWidth;
396→        const clampedOffset = Math.max(halfWidth, Math.min(maxOffset, newOffset));
397→
398→        const updateType = selectedType === 'door' ? 'DOOR_UPDATE' : 'WINDOW_UPDATE';
399→        dispatch({
400→          type: updateType,
401→          floorId: activeFloorId,
402→          [selectedType]: { id: item.id, offset: clampedOffset },
403→        });
404→
405→        editorDispatch({
406→          type: 'UPDATE_TOOL_STATE',
407→          payload: { startPos: modelPos },
408→        });
409→      }
410→    },
411→
412→    onMouseUp(modelPos, e, toolState) {
413→      if (toolState.dragging && toolState.dragType === 'marquee') {
414→        const floor = getFloor(activeFloorId);
415→        const bounds = normalizeRectBounds(toolState.startPos || modelPos, toolState.currentPos || modelPos);
416→        const size = rectSize(bounds);
417→        const minimumSize = SNAP_DISTANCE_PX / viewport.zoom;
418→
419→        if (!floor || (size.width < minimumSize && size.height < minimumSize)) {
420→          editorDispatch({ type: 'DESELECT' });
421→        } else {
422→          const regionSelection = collectPlanRegionSelection(floor, bounds);
423→          if (regionSelection.objectCount) {
424→            editorDispatch({
425→              type: 'SET_REGION_SELECTION',
426→              bounds: regionSelection.bounds,
427→              selection: regionSelection.selection,
428→            });
429→          } else {
430→            editorDispatch({ type: 'DESELECT' });
431→          }
432→        }
433→
434→        editorDispatch({
435→          type: 'UPDATE_TOOL_STATE',
436→          payload: {
437→            dragging: false,
438→            dragType: null,
439→            handle: null,
440→            handleIndex: null,
441→            startPos: null,
442→            currentPos: null,
443→          },
444→        });
445→        return;
446→      }
447→
448→      if (toolState.dragging) {
449→        editorDispatch({
450→          type: 'UPDATE_TOOL_STATE',
451→          payload: {
452→            dragging: false,
453→            dragType: null,
454→            handle: null,
455→            handleIndex: null,
456→            startPos: null,
457→            originalPos: null,
458→            currentPos: null,
459→          },
460→        });
461→      }
462→    },
463→
464→    onKeyDown(e, toolState, selectedId, selectedType) {
465→      if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === 'd' && selectedId && selectedType === 'column') {
466→        e.preventDefault();
467→        const floor = getFloor(activeFloorId);
468→        if (!floor) return;
469→        const column = (floor.columns || []).find(c => c.id === selectedId);
470→        if (!column) return;
471→        const duplicate = duplicateColumn(column);
472→        dispatch({ type: 'COLUMN_DUPLICATE', floorId: activeFloorId, column: duplicate });
473→        editorDispatch({ type: 'SELECT_OBJECT', id: duplicate.id, objectType: 'column' });
474→        return;
475→      }
476→
477→      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
478→        const floor = getFloor(activeFloorId);
479→        if (!floor) return;
480→        if (selectedType === 'wall') {
481→          dispatch({ type: 'WALL_DELETE', floorId: activeFloorId, wallId: selectedId });
482→        } else if (selectedType === 'door') {
483→          dispatch({ type: 'DOOR_DELETE', floorId: activeFloorId, doorId: selectedId });
484→        } else if (selectedType === 'window') {
485→          dispatch({ type: 'WINDOW_DELETE', floorId: activeFloorId, windowId: selectedId });
486→        } else if (selectedType === 'column') {
487→          dispatch({ type: 'COLUMN_DELETE', floorId: activeFloorId, columnId: selectedId });
488→        } else if (selectedType === 'beam') {
489→          dispatch({ type: 'BEAM_DELETE', floorId: activeFloorId, beamId: selectedId });
490→        } else if (selectedType === 'stair') {
491→          dispatch({ type: 'STAIR_DELETE', floorId: activeFloorId, stairId: selectedId });
492→        } else if (selectedType === 'landing') {
493→          dispatch({ type: 'LANDING_DELETE', floorId: activeFloorId, landingId: selectedId });
494→        } else if (selectedType === 'annotation') {
495→          dispatch({ type: 'ANNOTATION_DELETE', floorId: activeFloorId, annotationId: selectedId });
496→        } else if (selectedType === 'slab') {
497→          dispatch({ type: 'SLAB_DELETE', floorId: activeFloorId, slabId: selectedId });
498→        } else if (selectedType === 'sectionCut') {
499→          dispatch({ type: 'SECTION_DELETE', floorId: activeFloorId, sectionId: selectedId });
500→        } else if (selectedType === 'room') {
501→          dispatch({ type: 'ROOM_DELETE', floorId: activeFloorId, roomId: selectedId });
502→        }
503→        editorDispatch({ type: 'DESELECT' });
504→      }
505→    },
506→
507→    getCursor(toolState) {
508→      if (toolState.dragType === 'marquee') return 'crosshair';
509→      if (toolState.dragging) return 'grabbing';
510→      return 'default';
511→    },
512→  };
513→}
