 87→      {/* Direction arrow line */}
 88→      <line
 89→        x1={arrowStart} y1={arrowY}
 90→        x2={arrowEnd} y2={arrowY}
 91→        stroke="var(--color-wall-fill)"
 92→        strokeWidth={1}
 93→        vectorEffect="non-scaling-stroke"
 94→      />
 95→      {/* Arrowhead */}
 96→      <polyline
 97→        points={`${arrowEnd - 6},${arrowY - 4} ${arrowEnd},${arrowY} ${arrowEnd - 6},${arrowY + 4}`}
 98→        fill="none"
 99→        stroke="var(--color-wall-fill)"
100→        strokeWidth={1}
101→        vectorEffect="non-scaling-stroke"
102→      />
103→    </g>
104→  );
