 15→
 16→function hitTest(modelPos, floor, annotationTolerance) {
 17→  // Hit test doors first (smaller targets, higher priority)
 18→  for (const door of floor.doors) {
 19→    const wall = floor.walls.find(w => w.id === door.wallId);
 20→    if (!wall) continue;
 21→    const info = doorOutlineOnWall(wall, door);
 22→    const poly = [info.p1, info.p2, info.p3, info.p4];
 23→    if (pointInPolygon(modelPos, poly)) {
 24→      return { id: door.id, type: 'door' };
 25→    }
 26→  }
 27→
 28→  // Hit test windows
 29→  for (const win of floor.windows) {
 30→    const wall = floor.walls.find(w => w.id === win.wallId);
 31→    if (!wall) continue;
 32→    const info = windowOutlineOnWall(wall, win);
 33→    const poly = [info.p1, info.p2, info.p3, info.p4];
 34→    if (pointInPolygon(modelPos, poly)) {
 35→      return { id: win.id, type: 'window' };
 36→    }
 37→  }
 38→
 39→  // Hit test walls
 40→  // Hit test columns
 41→  for (const sc of (floor.sectionCuts || [])) {
 42→    if (hitTestSectionCut(modelPos, sc, annotationTolerance)) {
 43→      return { id: sc.id, type: 'sectionCut' };
 44→    }
 45→  }
 46→
 47→  for (const column of (floor.columns || [])) {
 48→    const outline = columnOutline(column);
 49→    if (pointInPolygon(modelPos, outline)) {
 50→      return { id: column.id, type: 'column' };
 51→    }
 52→  }
 53→
 54→  // Hit test beams
 55→  for (const beam of (floor.beams || [])) {
 56→    const renderData = getBeamRenderData(beam, floor.columns || []);
 57→    if (!renderData) continue;
 58→    if (pointInPolygon(modelPos, renderData.outline)) {
 59→      return { id: beam.id, type: 'beam' };
 60→    }
 61→  }
 62→
 63→  // Hit test walls
 64→  for (const wall of floor.walls) {
 65→    const outline = getWallRenderData(wall, floor.columns || []).outline;
 66→    if (pointInPolygon(modelPos, outline)) {
 67→      return { id: wall.id, type: 'wall' };
 68→    }
 69→  }
 70→
 71→  // Hit test stairs after walls/beams/columns so current editing priority stays intact.
 72→  for (const stair of (floor.stairs || [])) {
 73→    const renderData = getStairRenderData(stair);
 74→    if (!renderData) continue;
 75→    if (pointInPolygon(modelPos, renderData.outline)) {
 76→      return { id: stair.id, type: 'stair' };
 77→    }
 78→  }
 79→
 80→  // Hit test landings
 81→  for (const landing of (floor.landings || [])) {
 82→    if (landingContainsPoint(landing, modelPos)) {
 83→      return { id: landing.id, type: 'landing' };
 84→    }
 85→  }
 86→
 87→  // Hit test rooms (lowest priority)
 88→  for (const room of floor.rooms) {
 89→    if (room.points?.length >= 3 && pointInPolygon(modelPos, room.points)) {
 90→      return { id: room.id, type: 'room' };
 91→    }
 92→  }
 93→
 94→  for (const slab of (floor.slabs || [])) {
 95→    if (slabContainsPoint(slab, modelPos)) {
 96→      return { id: slab.id, type: 'slab' };
 97→    }
 98→  }
 99→
100→  const annotationHit = hitTestAnnotation(modelPos, floor, annotationTolerance);
101→  if (annotationHit) {
102→    return annotationHit;
103→  }
104→
105→  return null;
106→}
