31→    onMouseDown(modelPos, e, toolState) {
32→      if (e.button !== 0) return;
33→
34→      const floor = getFloor(activeFloorId);
35→      if (!floor) return;
36→
37→      const column = findColumnAtPoint(floor.columns || [], modelPos);
38→      if (!column) {
39→        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Click a column to place a beam.' });
40→        return;
41→      }
42→
43→      if (!toolState.startColumnId) {
44→        editorDispatch({
45→          type: 'UPDATE_TOOL_STATE',
