446→      }
447→
448→      if (toolState.dragging) {
449→        editorDispatch({
450→          type: 'UPDATE_TOOL_STATE',
451→          payload: {
452→            dragging: false,
453→            dragType: null,
454→            handle: null,
455→            handleIndex: null,
456→            startPos: null,
457→            originalPos: null,
458→            currentPos: null,
459→          },
