30→export function useEditorTool({ activeTool, dispatch, editorDispatch, project, getFloor, activeFloorId, viewport, snapEnabled, selectedId, selectedType, toolState, viewMode }) {
31→  const getFloorRef = useRef(getFloor);
32→  getFloorRef.current = getFloor;
33→
34→  const handler = useMemo(() => {
35→    if (viewMode?.startsWith('elevation_')) {
36→      return createElevationSelectHandler({
37→        dispatch,
38→        editorDispatch,
39→        project,
40→        getFloor: (...args) => getFloorRef.current(...args),
41→        activeFloorId,
42→        viewport,
43→        snapEnabled,
44→        viewMode,
45→      });
46→    }
47→
48→    if (viewMode !== 'plan') {
49→      return createReadOnlyHandler();
50→    }
51→
52→    const ctx = {
53→      dispatch, editorDispatch,
54→      getFloor: (...args) => getFloorRef.current(...args),
55→      activeFloorId, viewport, snapEnabled,
56→    };
57→
58→    switch (activeTool) {
59→      case TOOLS.DIMENSION:
60→        return createDimensionPlaceHandler(ctx);
61→      case TOOLS.WALL:
62→        return createWallDrawHandler(ctx);
63→      case TOOLS.BEAM:
64→        return createBeamPlaceHandler(ctx);
65→      case TOOLS.STAIR:
66→        return createStairPlaceHandler(ctx);
67→      case TOOLS.SECTION:
68→        return createSectionPlaceHandler(ctx);
69→      case TOOLS.SLAB:
70→        return createSlabPlaceHandler(ctx);
71→      case TOOLS.ROOM:
72→        return createRoomPlaceHandler(ctx);
73→      case TOOLS.SELECT:
74→        return createSelectHandler(ctx);
75→      case TOOLS.DOOR:
76→        return createDoorPlaceHandler(ctx);
77→      case TOOLS.WINDOW:
78→        return createWindowPlaceHandler(ctx);
79→      case TOOLS.COLUMN:
80→        return createColumnPlaceHandler(ctx);
81→      case TOOLS.LANDING:
82→        return createLandingPlaceHandler(ctx);
83→      default:
84→        return null;
85→    }
86→  }, [activeTool, activeFloorId, project, viewport.zoom, snapEnabled, viewMode]);
87→
88→  return {
89→    onMouseDown: (modelPos, e) => handler?.onMouseDown?.(modelPos, e, toolState),
90→    onMouseMove: (modelPos, e) => handler?.onMouseMove?.(modelPos, e, toolState, selectedId, selectedType),
91→    onMouseUp: (modelPos, e) => handler?.onMouseUp?.(modelPos, e, toolState),
92→    onDoubleClick: (modelPos, e) => handler?.onDoubleClick?.(modelPos, e, toolState),
93→    onKeyDown: (e) => handler?.onKeyDown?.(e, toolState, selectedId, selectedType),
94→    getCursor: () => handler?.getCursor?.(toolState) || 'default',
95→  };
96→}
