 1→import { rotate, midpoint, normalize, subtract, perpendicular, scale, add } from './point';
 2→
 3→export function columnCenter(column) {
 4→  return { x: column.x, y: column.y };
 5→}
 6→
 7→export function columnAxes(column) {
 8→  const angle = ((column.rotation || 0) * Math.PI) / 180;
 9→  const xAxis = { x: Math.cos(angle), y: Math.sin(angle) };
10→  const yAxis = { x: -Math.sin(angle), y: Math.cos(angle) };
11→  return { xAxis, yAxis };
12→}
13→
14→export function columnOutline(column) {
15→  const hw = column.width / 2, hd = column.depth / 2;
16→  const { x: cx, y: cy } = column;
17→  const corners = [
18→    { x: cx - hw, y: cy - hd }, { x: cx + hw, y: cy - hd },
19→    { x: cx + hw, y: cy + hd }, { x: cx - hw, y: cy + hd },
20→  ];
21→  if (!column.rotation) return corners;
22→  return corners.map(p => rotate(p, { x: cx, y: cy }, column.rotation));
23→}
24→
25→export function columnEdgeMidpoints(column) {
26→  const corners = columnOutline(column);
27→  return [
28→    midpoint(corners[0], corners[1]),
29→    midpoint(corners[1], corners[2]),
30→    midpoint(corners[2], corners[3]),
31→    midpoint(corners[3], corners[0]),
32→  ];
33→}
34→
35→export function columnEdges(column) {
36→  const corners = columnOutline(column);
37→  return corners.map((c, i) => ({
38→    index: i,
39→    start: c,
40→    end: corners[(i + 1) % corners.length],
41→  }));
42→}
43→
44→export function columnFaces(column) {
45→  return columnEdges(column).map((edge) => {
46→    const tangent = normalize(subtract(edge.end, edge.start));
47→    const inwardNormal = perpendicular(tangent);
48→    return {
49→      ...edge,
50→      midpoint: midpoint(edge.start, edge.end),
51→      tangent,
52→      outwardNormal: scale(inwardNormal, -1),
53→      length: Math.hypot(edge.end.x - edge.start.x, edge.end.y - edge.start.y),
54→    };
55→  });
56→}
57→
58→export function columnCenterlines(column) {
59→  const center = columnCenter(column);
60→  const { xAxis, yAxis } = columnAxes(column);
61→
62→  return [
63→    {
64→      index: 0,
65→      axis: xAxis,
66→      halfLength: column.width / 2,
67→      start: add(center, scale(xAxis, -column.width / 2)),
68→      end: add(center, scale(xAxis, column.width / 2)),
69→    },
70→    {
71→      index: 1,
72→      axis: yAxis,
73→      halfLength: column.depth / 2,
74→      start: add(center, scale(yAxis, -column.depth / 2)),
75→      end: add(center, scale(yAxis, column.depth / 2)),
76→    },
77→  ];
78→}
79→
80→export function columnSnapPoints(column) {
81→  return [
82→    { x: column.x, y: column.y },
83→    ...columnOutline(column),
84→    ...columnEdgeMidpoints(column),
85→  ];
86→}
87→
88→export function columnWallSnapPoints(column) {
89→  return [
90→    ...columnOutline(column),
91→    ...columnEdgeMidpoints(column),
92→  ];
93→}
