  1→import { DOOR_HEIGHT, DOOR_SILL_HEIGHT, SLAB_ELEVATION, SLAB_THICKNESS, STAIR_RISERS, STAIR_RISER_HEIGHT, STAIR_TREAD_DEPTH, STAIR_WIDTH, WALL_HEIGHT, WINDOW_HEIGHT, WINDOW_SILL_HEIGHT } from '@/domain/defaults';
  2→import { createFloor } from '@/domain/models';
  3→import { createAnnotationSettings } from '@/domain/models';
  4→import { getDefaultActiveFloorId, getFloorElevation, getFloorLevelIndex, getFloorToFloorHeight, sortFloors } from '@/domain/floorModels';
  5→
  6→export function deserializeProject(json) {
  7→  if (!json || !json.version || !json.data) {
  8→    throw new Error('Invalid project data');
  9→  }
 10→  if (json.version !== 1) {
 11→    throw new Error(`Unsupported project version: ${json.version}`);
 12→  }
 13→
 14→  const project = json.data;
 15→
 16→  // Basic validation
 17→  if (!project.id || !project.name || !Array.isArray(project.floors)) {
 18→    throw new Error('Invalid project structure');
 19→  }
 20→
 21→  if (!Array.isArray(project.sheets)) {
 22→    project.sheets = [];
 23→  }
 24→
 25→  if (project.floors.length === 0) {
 26→    project.floors = [createFloor('Ground Floor', 0)];
 27→  }
 28→
 29→  for (const floor of project.floors) {
 30→    if (!floor.id || !Array.isArray(floor.walls)) {
 31→      throw new Error('Invalid floor structure');
 32→    }
 33→  }
 34→
 35→  // Backfill missing room fields for old saves
 36→  project.floors.forEach((floor, index) => {
 37→    if (!floor.name) floor.name = index === 0 ? 'Ground Floor' : `Floor ${index}`;
 38→    if (floor.levelIndex === undefined) {
 39→      floor.levelIndex = floor.level ?? index;
 40→    }
 41→    if (floor.floorToFloorHeight === undefined) {
 42→      floor.floorToFloorHeight = WALL_HEIGHT;
 43→    }
 44→    if (floor.elevation === undefined) {
 45→      floor.elevation = floor.level ?? (floor.levelIndex * floor.floorToFloorHeight);
 46→    }
 47→    delete floor.level;
 48→
 49→    if (!floor.rooms) floor.rooms = [];
 50→    for (const room of floor.rooms) {
 51→      if (!room.points) room.points = [];
 52→      if (room.area === undefined) room.area = 0;
 53→    }
 54→  });
 55→
 56→  // Backfill door/window type fields for old saves
 57→  for (const floor of project.floors) {
 58→    if (!floor.doors) floor.doors = [];
 59→    for (const door of floor.doors) {
 60→      if (!door.type) door.type = 'swing';
 61→      if (door.height === undefined) door.height = DOOR_HEIGHT;
 62→      if (door.sillHeight === undefined) door.sillHeight = DOOR_SILL_HEIGHT;
 63→    }
 64→    if (!floor.windows) floor.windows = [];
 65→    for (const win of floor.windows) {
 66→      if (!win.type) win.type = 'standard';
 67→      if (!win.openDirection) win.openDirection = 'left';
 68→      if (win.height === undefined) win.height = WINDOW_HEIGHT;
 69→      if (win.sillHeight === undefined) win.sillHeight = WINDOW_SILL_HEIGHT;
 70→    }
 71→    if (!floor.columns) floor.columns = [];
 72→    if (!floor.beams) floor.beams = [];
 73→    if (!floor.stairs) floor.stairs = [];
 74→    if (!floor.landings) floor.landings = [];
 75→    if (!floor.annotations) floor.annotations = [];
 76→    floor.annotationSettings = createAnnotationSettings(floor.annotationSettings || {});
 77→    // Migrate single slab → slabs array
 78→    if (floor.slab !== undefined) {
 79→      floor.slabs = floor.slab ? [floor.slab] : [];
 80→      delete floor.slab;
 81→    }
 82→    if (!Array.isArray(floor.slabs)) floor.slabs = [];
 83→    // Migrate single sectionCut → sectionCuts array
 84→    if (floor.sectionCut !== undefined) {
 85→      floor.sectionCuts = floor.sectionCut ? [floor.sectionCut] : [];
 86→      delete floor.sectionCut;
 87→    }
 88→    if (!Array.isArray(floor.sectionCuts)) floor.sectionCuts = [];
 89→    for (const wall of floor.walls) {
 90→      if (wall.height === undefined) wall.height = WALL_HEIGHT;
 91→      if (wall.startAttachment === undefined) wall.startAttachment = null;
 92→      if (wall.endAttachment === undefined) wall.endAttachment = null;
 93→    }
 94→    for (const column of floor.columns) {
 95→      if (column.showLabel === undefined) {
 96→        column.showLabel = Boolean(column.name);
 97→      }
 98→    }
 99→    for (const beam of floor.beams) {
100→      if (beam.floorLevel === undefined) beam.floorLevel = getFloorElevation(floor, index);
101→    }
102→    for (const stair of floor.stairs) {
103→      if (!stair.startPoint) stair.startPoint = { x: 0, y: 0 };
104→      if (stair.width === undefined) stair.width = STAIR_WIDTH;
105→      if (stair.numberOfRisers === undefined) stair.numberOfRisers = STAIR_RISERS;
106→      if (stair.riserHeight === undefined) stair.riserHeight = STAIR_RISER_HEIGHT;
107→      if (stair.treadDepth === undefined) stair.treadDepth = STAIR_TREAD_DEPTH;
108→      if (stair.direction === undefined) {
109→        stair.direction = { angle: 0 };
110→      } else if (typeof stair.direction === 'number') {
111→        stair.direction = { angle: stair.direction };
112→      } else if (stair.direction.angle === undefined) {
113→        stair.direction.angle = 0;
114→      }
115→      if (stair.floorRelation === undefined) {
116→        stair.floorRelation = { fromFloorId: floor.id, toFloorId: floor.id };
117→      } else {
118→        if (stair.floorRelation.fromFloorId === undefined) stair.floorRelation.fromFloorId = floor.id;
119→        if (stair.floorRelation.toFloorId === undefined) stair.floorRelation.toFloorId = floor.id;
120→      }
121→      if (stair.startLandingAttachment === undefined) stair.startLandingAttachment = null;
122→      if (stair.endLandingAttachment === undefined) stair.endLandingAttachment = null;
123→    }
124→    for (const landing of floor.landings) {
125→      if (!landing.position) landing.position = { x: 0, y: 0 };
126→      if (landing.width === undefined) landing.width = 1000;
127→      if (landing.depth === undefined) landing.depth = 1000;
128→      if (landing.thickness === undefined) landing.thickness = 200;
129→      if (landing.elevation === undefined) landing.elevation = 0;
130→      if (landing.rotation === undefined) landing.rotation = 0;
131→    }
132→    for (const annotation of floor.annotations) {
133→      if (!annotation.id) {
134→        annotation.id = `anno_${floor.id}_${Math.random().toString(36).slice(2, 8)}`;
135→      }
136→      if (!annotation.type) annotation.type = 'dimension';
137→      if (!annotation.mode) annotation.mode = 'aligned';
138→      if (!annotation.startPoint) annotation.startPoint = { x: 0, y: 0 };
139→      if (!annotation.endPoint) annotation.endPoint = { x: 0, y: 0 };
140→      if (annotation.offset === undefined) annotation.offset = 300;
141→      if (annotation.textOverride === undefined) annotation.textOverride = '';
142→    }
143→    for (const slab of floor.slabs) {
144→      if (!slab.floorId) slab.floorId = floor.id;
145→      if (!slab.boundaryPoints) slab.boundaryPoints = [];
146→      if (slab.thickness === undefined) slab.thickness = SLAB_THICKNESS;
147→      if (slab.elevation === undefined) slab.elevation = SLAB_ELEVATION;
148→      if (slab.name === undefined) slab.name = '';
149→      if (slab.type === undefined) slab.type = '';
150→    }
151→    for (const sc of floor.sectionCuts) {
152→      if (!sc.id) {
153→        sc.id = `section_${floor.id}_${Math.random().toString(36).slice(2, 8)}`;
154→      }
155→      if (!sc.startPoint) sc.startPoint = { x: 0, y: 0 };
156→      if (!sc.endPoint) sc.endPoint = { x: 1000, y: 0 };
157→      if (sc.depth === undefined) sc.depth = 2000;
158→      if (sc.label === undefined) sc.label = 'Section A-A';
159→      if (sc.direction === undefined) sc.direction = 1;
160→    }
161→  }
162→
163→  project.floors = sortFloors(project.floors).map((floor, index) => ({
164→    ...floor,
165→    levelIndex: getFloorLevelIndex(floor, index),
166→    elevation: getFloorElevation(floor, index),
167→    floorToFloorHeight: getFloorToFloorHeight(floor),
168→  }));
169→
170→  for (const sheet of project.sheets) {
171→    if (!sheet.id) {
172→      sheet.id = `sheet_${Math.random().toString(36).slice(2, 8)}`;
173→    }
174→    if (sheet.title === undefined) sheet.title = '';
175→    if (sheet.paperSize === undefined) sheet.paperSize = 'A3_LANDSCAPE';
176→    if (sheet.scaleLabel === undefined) sheet.scaleLabel = '1:100';
177→    if (sheet.drawingName === undefined) sheet.drawingName = sheet.title || 'Drawing';
178→    if (sheet.projectNameOverride === undefined) sheet.projectNameOverride = '';
179→    if (!Array.isArray(sheet.viewports)) sheet.viewports = [];
180→
181→    for (const viewport of sheet.viewports) {
182→      if (!viewport.id) {
183→        viewport.id = `viewport_${sheet.id}_${Math.random().toString(36).slice(2, 8)}`;
184→      }
185→      if (viewport.sourceView === undefined) viewport.sourceView = 'plan';
186→      if (viewport.sourceFloorId === undefined) viewport.sourceFloorId = getDefaultActiveFloorId(project);
187→      if (viewport.sourceRefId === undefined) viewport.sourceRefId = null;
188→      if (viewport.x === undefined) viewport.x = 20;
189→      if (viewport.y === undefined) viewport.y = 20;
190→      if (viewport.width === undefined) viewport.width = 160;
191→      if (viewport.height === undefined) viewport.height = 100;
192→      if (viewport.scale === undefined) viewport.scale = 100;
193→      if (viewport.title === undefined) viewport.title = '';
194→      if (viewport.rotation === undefined) viewport.rotation = 0;
195→    }
196→  }
197→
198→  return { project, savedAt: json.savedAt };
199→}
