  1→import { buildManualDimensionFigures } from '@/annotations/dimensions';
  2→import { generateId } from '@/domain/ids';
  3→import { getBeamRenderData } from '@/geometry/beamGeometry';
  4→import { columnOutline } from '@/geometry/columnGeometry';
  5→import { segmentIntersection } from '@/geometry/line';
  6→import { pointInPolygon } from '@/geometry/polygon';
  7→import { getSectionCutRenderData } from '@/geometry/sectionCutGeometry';
  8→import { getSlabRenderData } from '@/geometry/slabGeometry';
  9→import { getLandingRenderData } from '@/geometry/landingGeometry';
 10→import { getStairRenderData } from '@/geometry/stairGeometry';
 11→import { getWallRenderData } from '@/geometry/wallColumnGeometry';
 12→import { doorOutlineOnWall, windowOutlineOnWall } from '@/geometry/wallGeometry';
 13→
 14→const PLAN_KEYS = ['walls', 'doors', 'windows', 'columns', 'beams', 'stairs', 'landings', 'annotations', 'slabs', 'sectionCuts', 'rooms'];
 15→
 16→function translatePoint(point, dx, dy) {
 17→  return { x: point.x + dx, y: point.y + dy };
 18→}
 19→
 20→function rectPoints(bounds) {
 21→  return [
 22→    { x: bounds.minX, y: bounds.minY },
 23→    { x: bounds.maxX, y: bounds.minY },
 24→    { x: bounds.maxX, y: bounds.maxY },
 25→    { x: bounds.minX, y: bounds.maxY },
 26→  ];
 27→}
 28→
 29→function pointInRect(point, bounds) {
 30→  return point.x >= bounds.minX &&
 31→    point.x <= bounds.maxX &&
 32→    point.y >= bounds.minY &&
 33→    point.y <= bounds.maxY;
 34→}
 35→
 36→function segmentIntersectsRect(start, end, bounds) {
 37→  if (pointInRect(start, bounds) || pointInRect(end, bounds)) return true;
 38→
 39→  const rect = rectPoints(bounds);
 40→  for (let index = 0; index < rect.length; index += 1) {
 41→    const hit = segmentIntersection(start, end, rect[index], rect[(index + 1) % rect.length]);
 42→    if (hit) return true;
 43→  }
 44→
 45→  return false;
 46→}
 47→
 48→function polygonIntersectsRect(points, bounds) {
 49→  if (!points?.length) return false;
 50→  if (points.some((point) => pointInRect(point, bounds))) return true;
 51→
 52→  const rect = rectPoints(bounds);
 53→  if (rect.some((point) => pointInPolygon(point, points))) return true;
 54→
 55→  for (let index = 0; index < points.length; index += 1) {
 56→    if (segmentIntersectsRect(points[index], points[(index + 1) % points.length], bounds)) {
 57→      return true;
 58→    }
 59→  }
 60→
 61→  return false;
 62→}
 63→
 64→function geometryIntersectsRect(geometry, bounds) {
 65→  if (!geometry) return false;
 66→  if (geometry.polygon) return polygonIntersectsRect(geometry.polygon, bounds);
 67→  if (geometry.segments) {
 68→    return geometry.segments.some((segment) => segmentIntersectsRect(segment.start, segment.end, bounds));
 69→  }
 70→  return false;
 71→}
 72→
 73→function collectGeometryPoints(geometry) {
 74→  if (!geometry) return [];
 75→  if (geometry.polygon) return geometry.polygon;
 76→  if (geometry.segments) {
 77→    return geometry.segments.flatMap((segment) => [segment.start, segment.end]);
 78→  }
 79→  return [];
 80→}
 81→
 82→function cloneAttachment(attachment, nextColumnId = attachment?.columnId ?? null) {
 83→  if (!attachment) return null;
 84→  if (!nextColumnId) return null;
 85→  return {
 86→    ...attachment,
 87→    columnId: nextColumnId,
 88→  };
 89→}
 90→
 91→function createEmptyMap() {
 92→  return PLAN_KEYS.reduce((acc, key) => {
 93→    acc[key] = [];
 94→    return acc;
 95→  }, {});
 96→}
 97→
 98→function toIdSetMap(selection = createEmptyMap()) {
 99→  return PLAN_KEYS.reduce((acc, key) => {
100→    acc[key] = new Set(selection[key] || []);
101→    return acc;
102→  }, {});
103→}
104→
105→function countSelection(selection = createEmptyMap()) {
106→  return PLAN_KEYS.reduce((count, key) => count + (selection[key]?.length || 0), 0);
107→}
108→
109→function countContent(content = createEmptyMap()) {
110→  return PLAN_KEYS.reduce((count, key) => count + (content[key]?.length || 0), 0);
111→}
