113→function idPrefixForKey(key) {
114→  switch (key) {
115→    case 'walls':
116→      return 'wall';
117→    case 'doors':
118→      return 'door';
119→    case 'windows':
120→      return 'win';
121→    case 'columns':
122→      return 'col';
123→    case 'beams':
124→      return 'beam';
125→    case 'stairs':
126→      return 'stair';
127→    case 'landings':
128→      return 'landing';
129→    case 'annotations':
130→      return 'anno';
131→    case 'slabs':
132→      return 'slab';
133→    case 'sectionCuts':
