142→function iteratePlanGeometry(floor, visit) {
143→  const walls = floor?.walls || [];
144→  const columns = floor?.columns || [];
145→
146→  for (const wall of walls) {
147→    visit('walls', wall.id, wall, {
148→      polygon: getWallRenderData(wall, columns).outline,
149→    });
150→  }
151→
152→  for (const door of floor?.doors || []) {
153→    const wall = walls.find((entry) => entry.id === door.wallId);
154→    if (!wall) continue;
155→    const info = doorOutlineOnWall(wall, door);
156→    visit('doors', door.id, door, {
157→      polygon: [info.p1, info.p2, info.p3, info.p4],
158→    });
159→  }
160→
161→  for (const window_ of floor?.windows || []) {
162→    const wall = walls.find((entry) => entry.id === window_.wallId);
163→    if (!wall) continue;
164→    const info = windowOutlineOnWall(wall, window_);
165→    visit('windows', window_.id, window_, {
166→      polygon: [info.p1, info.p2, info.p3, info.p4],
167→    });
168→  }
169→
170→  for (const column of columns) {
171→    visit('columns', column.id, column, {
172→      polygon: columnOutline(column),
173→    });
174→  }
175→
176→  for (const beam of floor?.beams || []) {
177→    const renderData = getBeamRenderData(beam, columns);
178→    if (!renderData) continue;
179→    visit('beams', beam.id, beam, {
180→      polygon: renderData.outline,
181→    });
182→  }
183→
184→  for (const stair of floor?.stairs || []) {
185→    const renderData = getStairRenderData(stair);
186→    if (!renderData) continue;
187→    visit('stairs', stair.id, stair, {
188→      polygon: renderData.outline,
189→    });
190→  }
191→
192→  for (const landing of floor?.landings || []) {
193→    const renderData = getLandingRenderData(landing);
194→    if (!renderData) continue;
195→    visit('landings', landing.id, landing, {
196→      polygon: renderData.outline,
197→    });
198→  }
199→
200→  for (const annotation of floor?.annotations || []) {
201→    const figure = buildManualDimensionFigures([annotation])[0];
202→    if (!figure) continue;
203→    visit('annotations', annotation.id, annotation, {
204→      segments: figure.segments,
205→    });
206→  }
207→
208→  for (const slab of floor?.slabs || []) {
209→    const renderData = getSlabRenderData(slab);
210→    if (!renderData) continue;
211→    visit('slabs', slab.id, slab, {
212→      polygon: renderData.outline,
213→    });
214→  }
215→
216→  for (const sectionCut of floor?.sectionCuts || []) {
217→    const renderData = getSectionCutRenderData(sectionCut);
218→    if (!renderData) continue;
219→    visit('sectionCuts', sectionCut.id, sectionCut, {
220→      segments: [{
221→        start: renderData.line.start,
222→        end: renderData.line.end,
223→      }],
224→    });
225→  }
226→
227→  for (const room of floor?.rooms || []) {
228→    if (!room.points?.length) continue;
229→    visit('rooms', room.id, room, {
230→      polygon: room.points,
231→    });
232→  }
233→}
