344→function translateStair(stair, point) {
345→  return {
346→    ...stair,
347→    startPoint: translatePoint(stair.startPoint, point.x, point.y),
348→    floorRelation: {
349→      fromFloorId: stair.floorRelation?.fromFloorId ?? null,
350→      toFloorId: stair.floorRelation?.toFloorId ?? null,
351→    },
352→    startLandingAttachment: stair.startLandingAttachment ? { ...stair.startLandingAttachment } : null,
353→    endLandingAttachment: stair.endLandingAttachment ? { ...stair.endLandingAttachment } : null,
354→  };
355→}
