364→function translateAnnotation(annotation, point) {
365→  return {
366→    ...annotation,
367→    startPoint: translatePoint(annotation.startPoint, point.x, point.y),
368→    endPoint: translatePoint(annotation.endPoint, point.x, point.y),
369→  };
