397→function translateContent(content, point) {
398→  return {
399→    walls: (content.walls || []).map((wall) => translateWall(wall, point)),
400→    doors: (content.doors || []).map((door) => ({ ...door })),
401→    windows: (content.windows || []).map((window_) => ({ ...window_ })),
402→    columns: (content.columns || []).map((column) => translateColumn(column, point)),
403→    beams: (content.beams || []).map((beam) => ({
404→      ...beam,
405→      startRef: beam.startRef ? { ...beam.startRef } : null,
406→      endRef: beam.endRef ? { ...beam.endRef } : null,
407→    })),
408→    stairs: (content.stairs || []).map((stair) => translateStair(stair, point)),
409→    landings: (content.landings || []).map((landing) => translateLanding(landing, point)),
410→    annotations: (content.annotations || []).map((annotation) => translateAnnotation(annotation, point)),
411→    slabs: (content.slabs || []).map((slab) => translateSlab(slab, point)),
412→    sectionCuts: (content.sectionCuts || []).map((sectionCut) => translateSectionCut(sectionCut, point)),
413→    rooms: (content.rooms || []).map((room) => translateRoom(room, point)),
414→  };
