417→function buildContentBounds(content) {
418→  const floorLike = { ...content };
419→  const points = [];
420→
421→  iteratePlanGeometry(floorLike, (_, __, ___, geometry) => {
422→    points.push(...collectGeometryPoints(geometry));
423→  });
424→
425→  if (!points.length) return null;
426→
427→  const xs = points.map((point) => point.x);
428→  const ys = points.map((point) => point.y);
429→  return {
430→    minX: Math.min(...xs),
431→    minY: Math.min(...ys),
432→    maxX: Math.max(...xs),
433→    maxY: Math.max(...ys),
434→  };
435→}
