492→export function buildPlanClipboardPayload({ projectId, floorId, floor, regionSelection }) {
493→  const selection = regionSelection?.selection || createEmptyPlanSelection();
494→  const selectionSets = toIdSetMap(selection);
495→  const anchor = {
496→    x: regionSelection?.bounds?.minX || 0,
497→    y: regionSelection?.bounds?.minY || 0,
498→  };
499→  const content = createEmptyPlanContent();
500→
501→  content.walls = (floor.walls || [])
502→    .filter((wall) => selectionSets.walls.has(wall.id))
503→    .map((wall) => rebaseWall(wall, anchor, selectionSets.columns));
504→
505→  content.columns = (floor.columns || [])
506→    .filter((column) => selectionSets.columns.has(column.id))
507→    .map((column) => rebaseColumn(column, anchor));
508→
509→  content.doors = (floor.doors || [])
510→    .filter((door) => selectionSets.doors.has(door.id) && selectionSets.walls.has(door.wallId))
511→    .map((door) => rebaseDoor(door));
512→
513→  content.windows = (floor.windows || [])
514→    .filter((window_) => selectionSets.windows.has(window_.id) && selectionSets.walls.has(window_.wallId))
515→    .map((window_) => rebaseWindow(window_));
516→
517→  content.beams = (floor.beams || [])
518→    .filter((beam) => {
519→      if (!selectionSets.beams.has(beam.id)) return false;
520→      const startId = beam.startRef?.id;
521→      const endId = beam.endRef?.id;
522→      return selectionSets.columns.has(startId) && selectionSets.columns.has(endId);
523→    })
524→    .map((beam) => rebaseBeam(beam));
525→
526→  content.stairs = (floor.stairs || [])
527→    .filter((stair) => selectionSets.stairs.has(stair.id))
528→    .map((stair) => rebaseStair(stair, anchor));
529→
530→  content.landings = (floor.landings || [])
531→    .filter((landing) => selectionSets.landings.has(landing.id))
532→    .map((landing) => rebaseLanding(landing, anchor));
533→
534→  content.annotations = (floor.annotations || [])
535→    .filter((annotation) => selectionSets.annotations.has(annotation.id))
536→    .map((annotation) => rebaseAnnotation(annotation, anchor));
537→
538→  content.slabs = (floor.slabs || [])
539→    .filter((slab) => selectionSets.slabs.has(slab.id))
540→    .map((slab) => rebaseSlab(slab, anchor));
541→
542→  content.sectionCuts = (floor.sectionCuts || [])
543→    .filter((sectionCut) => selectionSets.sectionCuts.has(sectionCut.id))
544→    .map((sectionCut) => rebaseSectionCut(sectionCut, anchor));
545→
546→  content.rooms = (floor.rooms || [])
547→    .filter((room) => selectionSets.rooms.has(room.id))
548→    .map((room) => rebaseRoom(room, anchor));
549→
550→  return {
551→    sourceProjectId: projectId,
552→    sourceFloorId: floorId,
553→    sourceBounds: regionSelection?.bounds || null,
554→    sourceSelectionCount: regionSelection?.objectCount || 0,
555→    bounds: buildContentBounds(content),
556→    anchor,
557→    objectCount: countContent(content),
558→    content,
559→  };
560→}
