567→export function cutPlanSelectionFromFloor(floor, selection) {
568→  const selectionSets = toIdSetMap(selection);
569→  const selectedWallIds = selectionSets.walls;
570→  const selectedColumnIds = selectionSets.columns;
571→
572→  const nextWalls = (floor.walls || [])
573→    .filter((wall) => !selectedWallIds.has(wall.id))
574→    .map((wall) => ({
575→      ...wall,
576→      startAttachment: selectedColumnIds.has(wall.startAttachment?.columnId)
577→        ? null
578→        : cloneAttachment(wall.startAttachment),
579→      endAttachment: selectedColumnIds.has(wall.endAttachment?.columnId)
580→        ? null
581→        : cloneAttachment(wall.endAttachment),
582→    }));
583→
584→  const nextDoors = (floor.doors || []).filter((door) => (
585→    !selectionSets.doors.has(door.id) && !selectedWallIds.has(door.wallId)
586→  ));
587→
588→  const nextWindows = (floor.windows || []).filter((window_) => (
589→    !selectionSets.windows.has(window_.id) && !selectedWallIds.has(window_.wallId)
590→  ));
591→
592→  const nextColumns = (floor.columns || []).filter((column) => !selectedColumnIds.has(column.id));
593→  const nextColumnIds = new Set(nextColumns.map((column) => column.id));
594→
595→  const nextBeams = (floor.beams || []).filter((beam) => (
596→    !selectionSets.beams.has(beam.id) &&
597→    nextColumnIds.has(beam.startRef?.id) &&
598→    nextColumnIds.has(beam.endRef?.id)
599→  ));
600→
601→  return {
602→    ...floor,
603→    walls: nextWalls,
604→    doors: nextDoors,
605→    windows: nextWindows,
606→    columns: nextColumns,
607→    beams: nextBeams,
608→    stairs: (floor.stairs || []).filter((stair) => !selectionSets.stairs.has(stair.id)),
609→    landings: (floor.landings || []).filter((landing) => !selectionSets.landings.has(landing.id)),
610→    annotations: (floor.annotations || []).filter((annotation) => !selectionSets.annotations.has(annotation.id)),
611→    slabs: (floor.slabs || []).filter((slab) => !selectionSets.slabs.has(slab.id)),
612→    sectionCuts: (floor.sectionCuts || []).filter((sectionCut) => !selectionSets.sectionCuts.has(sectionCut.id)),
613→    rooms: (floor.rooms || []).filter((room) => !selectionSets.rooms.has(room.id)),
614→  };
615→}
