617→export function pastePlanClipboardOnFloor({ floor, floorId, payload, placementPoint }) {
618→  const translated = materializePlanClipboardContent(payload, placementPoint);
619→  if (!translated) {
620→    return {
621→      nextFloor: floor,
622→      insertedSelection: createEmptyPlanSelection(),
623→      insertedCount: 0,
624→      insertedBounds: null,
625→    };
626→  }
627→
628→  const idMaps = PLAN_KEYS.reduce((acc, key) => {
629→    acc[key] = new Map();
630→    return acc;
631→  }, {});
632→  const insertedSelection = createEmptyPlanSelection();
633→
634→  const nextColumns = (translated.columns || []).map((column) => {
635→    const nextId = generateId(idPrefixForKey('columns'));
636→    idMaps.columns.set(column.id, nextId);
637→    insertedSelection.columns.push(nextId);
638→    return {
639→      ...column,
640→      id: nextId,
641→    };
642→  });
643→
644→  const nextWalls = (translated.walls || []).map((wall) => {
645→    const nextId = generateId(idPrefixForKey('walls'));
646→    idMaps.walls.set(wall.id, nextId);
647→    insertedSelection.walls.push(nextId);
648→    return {
649→      ...wall,
650→      id: nextId,
651→      startAttachment: cloneAttachment(wall.startAttachment, idMaps.columns.get(wall.startAttachment?.columnId) || null),
652→      endAttachment: cloneAttachment(wall.endAttachment, idMaps.columns.get(wall.endAttachment?.columnId) || null),
653→    };
654→  });
655→
656→  const nextDoors = (translated.doors || []).flatMap((door) => {
657→    const nextWallId = idMaps.walls.get(door.wallId);
658→    if (!nextWallId) return [];
659→    const nextId = generateId(idPrefixForKey('doors'));
660→    idMaps.doors.set(door.id, nextId);
661→    insertedSelection.doors.push(nextId);
662→    return [{
663→      ...door,
664→      id: nextId,
665→      wallId: nextWallId,
666→    }];
667→  });
668→
669→  const nextWindows = (translated.windows || []).flatMap((window_) => {
670→    const nextWallId = idMaps.walls.get(window_.wallId);
671→    if (!nextWallId) return [];
672→    const nextId = generateId(idPrefixForKey('windows'));
673→    idMaps.windows.set(window_.id, nextId);
674→    insertedSelection.windows.push(nextId);
675→    return [{
676→      ...window_,
677→      id: nextId,
678→      wallId: nextWallId,
679→    }];
680→  });
681→
682→  const nextBeams = (translated.beams || []).flatMap((beam) => {
683→    const nextStartId = idMaps.columns.get(beam.startRef?.id);
684→    const nextEndId = idMaps.columns.get(beam.endRef?.id);
685→    if (!nextStartId || !nextEndId) return [];
686→
687→    const nextId = generateId(idPrefixForKey('beams'));
688→    idMaps.beams.set(beam.id, nextId);
689→    insertedSelection.beams.push(nextId);
690→
691→    return [{
692→      ...beam,
693→      id: nextId,
694→      startRef: beam.startRef ? { ...beam.startRef, id: nextStartId } : null,
695→      endRef: beam.endRef ? { ...beam.endRef, id: nextEndId } : null,
696→    }];
697→  });
698→
699→  const nextLandings = (translated.landings || []).map((landing) => {
700→    const nextId = generateId(idPrefixForKey('landings'));
701→    idMaps.landings.set(landing.id, nextId);
702→    insertedSelection.landings.push(nextId);
703→    return {
704→      ...landing,
705→      id: nextId,
706→    };
707→  });
708→
709→  const nextStairs = (translated.stairs || []).map((stair) => {
710→    const nextId = generateId(idPrefixForKey('stairs'));
711→    idMaps.stairs.set(stair.id, nextId);
712→    insertedSelection.stairs.push(nextId);
713→    return {
714→      ...stair,
715→      id: nextId,
716→      floorRelation: {
717→        fromFloorId: floorId,
718→        toFloorId: null,
719→      },
720→      startLandingAttachment: stair.startLandingAttachment
721→        ? { ...stair.startLandingAttachment, landingId: idMaps.landings.get(stair.startLandingAttachment.landingId) || stair.startLandingAttachment.landingId }
722→        : null,
723→      endLandingAttachment: stair.endLandingAttachment
724→        ? { ...stair.endLandingAttachment, landingId: idMaps.landings.get(stair.endLandingAttachment.landingId) || stair.endLandingAttachment.landingId }
725→        : null,
726→    };
727→  });
728→
729→  const nextAnnotations = (translated.annotations || []).map((annotation) => {
730→    const nextId = generateId(idPrefixForKey('annotations'));
731→    idMaps.annotations.set(annotation.id, nextId);
732→    insertedSelection.annotations.push(nextId);
733→    return {
734→      ...annotation,
735→      id: nextId,
736→    };
737→  });
738→
739→  const nextSlabs = (translated.slabs || []).map((slab) => {
740→    const nextId = generateId(idPrefixForKey('slabs'));
741→    idMaps.slabs.set(slab.id, nextId);
742→    insertedSelection.slabs.push(nextId);
743→    return {
744→      ...slab,
745→      id: nextId,
746→      floorId,
747→    };
748→  });
749→
750→  const nextSectionCuts = (translated.sectionCuts || []).map((sectionCut) => {
751→    const nextId = generateId(idPrefixForKey('sectionCuts'));
752→    idMaps.sectionCuts.set(sectionCut.id, nextId);
753→    insertedSelection.sectionCuts.push(nextId);
754→    return {
755→      ...sectionCut,
756→      id: nextId,
757→    };
758→  });
759→
760→  const nextRooms = (translated.rooms || []).map((room) => {
761→    const nextId = generateId(idPrefixForKey('rooms'));
762→    idMaps.rooms.set(room.id, nextId);
763→    insertedSelection.rooms.push(nextId);
764→    return {
765→      ...room,
766→      id: nextId,
767→    };
768→  });
769→
770→  const insertedContent = {
771→    walls: nextWalls,
772→    doors: nextDoors,
773→    windows: nextWindows,
774→    columns: nextColumns,
775→    beams: nextBeams,
776→    stairs: nextStairs,
777→    landings: nextLandings,
778→    annotations: nextAnnotations,
779→    slabs: nextSlabs,
780→    sectionCuts: nextSectionCuts,
781→    rooms: nextRooms,
782→  };
783→
784→  return {
785→    nextFloor: {
786→      ...floor,
787→      walls: [...(floor.walls || []), ...nextWalls],
788→      doors: [...(floor.doors || []), ...nextDoors],
789→      windows: [...(floor.windows || []), ...nextWindows],
790→      columns: [...(floor.columns || []), ...nextColumns],
791→      beams: [...(floor.beams || []), ...nextBeams],
792→      stairs: [...(floor.stairs || []), ...nextStairs],
793→      landings: [...(floor.landings || []), ...nextLandings],
794→      annotations: [...(floor.annotations || []), ...nextAnnotations],
795→      slabs: [...(floor.slabs || []), ...nextSlabs],
796→      sectionCuts: [...(floor.sectionCuts || []), ...nextSectionCuts],
797→      rooms: [...(floor.rooms || []), ...nextRooms],
798→    },
799→    insertedSelection,
800→    insertedCount: countSelection(insertedSelection),
801→    insertedBounds: buildContentBounds(insertedContent),
802→  };
803→}
